import React, { useState, useEffect } from "react";
import { Link } from "react-router-dom";
import "./Homebage.css";

const Navbar = () => {
  const [scrolled, setScrolled] = useState(false);

  useEffect(() => {
    const handleScroll = () => setScrolled(window.scrollY > 20);
    window.addEventListener("scroll", handleScroll);
    return () => window.removeEventListener("scroll", handleScroll);
  }, []);

  return (
    <nav className={`navbar ${scrolled ? "scrolled" : ""}`}>
      <div className="navbar-container">
        <div className="navbar-logo">
          <span className="logo-icon">🎓</span>
          <span className="logo-text">بوصلتي</span>
        </div>

        <div className="navbar-links">
          <Link to="/" className="nav-link">
            الرئيسية
          </Link>

          <Link to="/about" className="nav-link">
            من نحن
          </Link>

          <Link to="/login" className="nav-link">
            تسجيل دخول
          </Link>

          <Link to="/quiz" className="home-btn-primary">
            ابدأ الاختبار
          </Link>
        </div>

        <span className="hamburger">☰</span>
      </div>
    </nav>
  );
};

const HeroSection = () => (
  <section className="hero">
    <div className="hero-container">
      <div className="hero-text">
        <div className="hero-badge">BOUSALTY</div>

        <h1 className="hero-title">
          اكتشف تخصصك الجامعي المناسب
          <br />
          <span className="highlight">مع بوصلتك الذكية</span>
        </h1>

        <div className="gold-divider"></div>

        <p className="hero-subtitle">
          منصة ذكية تساعدك على تحليل ميولك ومهاراتك وتوجّهك نحو التخصص الأنسب
          لك بطريقة حديثة وواضحة.
        </p>

        <div className="hero-buttons">
          <Link to="/quiz" className="home-btn-primary">
            ابدأ التحليل 🚀
          </Link>

          <Link to="/login" className="home-btn-secondary">
            جرّب الآن
          </Link>
        </div>
      </div>

      <div className="hero-illustration">
        <div className="illustration-blob"></div>

        <div className="robot-card">
          <div className="robot-face">🤖</div>
          <p>AI Advisor</p>
        </div>

        <div className="student-card">
          <span className="student-icon">🧑‍🎓</span>
        </div>

        <div className="floating-card card-1">💡</div>
        <div className="floating-card card-2">📊</div>
        <div className="floating-card card-3">🎯</div>
      </div>
    </div>
  </section>
);

const HowItWorks = () => {
  const cards = [
    {
      icon: "🧠",
      title: "تحليل ذكي",
      desc: "نحلل شخصيتك وميولك الدراسية بطريقة مبسطة وحديثة.",
    },
    {
      icon: "📚",
      title: "اقتراح تخصصات",
      desc: "نقترح عليك التخصصات التي تناسب قدراتك وأهدافك المستقبلية.",
    },
    {
      icon: "🚀",
      title: "اتخاذ قرار بثقة",
      desc: "نساعدك على اختيار مسارك الأكاديمي بطريقة أوضح وأكثر ثقة.",
    },
  ];

  return (
    <section className="how-it-works">
      <div className="container">
        <div className="section-heading">
          <h2 className="section-title">كيف يعمل موقع بوصلتي؟</h2>
          <div className="gold-divider mx-auto"></div>
        </div>

        <div className="cards-grid">
          {cards.map((card, i) => (
            <div className="feature-card" key={i}>
              <div className="card-icon">{card.icon}</div>
              <h3 className="card-title">{card.title}</h3>
              <p className="card-desc">{card.desc}</p>
            </div>
          ))}
        </div>
      </div>
    </section>
  );
};

const ComparisonBanner = () => (
  <section className="comparison-banner">
    <div className="comparison-inner">
      <div className="comp-right">
        <span className="comp-icon">🎓</span>
        <span>اكتشف ميولك</span>
      </div>

      <div className="vs-circle">VS</div>

      <div className="comp-left">
        <span className="comp-icon">🤖</span>
        <span>حلّل شخصيتك</span>
      </div>
    </div>
  </section>
);

const ChatbotButton = () => <button className="chatbot-btn">💬</button>;

const HomePage = () => {
  return (
    <div className="home-page" dir="rtl">
      <Navbar />
      <HeroSection />
      <HowItWorks />
      <ComparisonBanner />
      <ChatbotButton />
    </div>
  );
};

export default HomePage;
